 1	import * as React from 'react';
 2	import { useCustomTranslation } from '@odf/shared';
 3	import {
 4	  Alert,
 5	  AlertVariant,
 6	  AlertActionLink,
 7	  AlertGroup,
 8	} from '@patternfly/react-core';
 9	
10	type ThirdPartyStorageWarningProps = {
11	  docHref: string;
12	  className?: string;
13	};
14	
15	const ThirdPartyStorageWarning: React.FC<ThirdPartyStorageWarningProps> = ({
16	  docHref,
17	  className,
18	}) => {
19	  const { t } = useCustomTranslation();
20	  return (
21	    <AlertGroup isLiveRegion>
22	      <Alert
23	        className={className}
24	        variant={AlertVariant.warning}
25	        title={t('Before you use Third-party storage')}
26	        actionLinks={
27	          <AlertActionLink
28	            component="a"
29	            href={docHref}
30	            target="_blank"
31	            rel="noopener noreferrer"
32	          >
33	            {t('View documentation')}
34	          </AlertActionLink>
35	        }
36	      >
37	        {t(
38	          `Ensure the third party storage supports Disaster Recovery pre-requisites and enable the required configuration for the same.`
39	        )}
40	      </Alert>
41	    </AlertGroup>
42	  );
43	};
44	
45	export default ThirdPartyStorageWarning;

